/**
 * Returns booked slot keys for the given car and week so the UI can lock them
 * @summary Get availability for a specific car and week
 */
export const getGetAvailabilityUrl = (params: GetAvailabilityParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/availability?${stringifiedParams}`
    : `/api/availability`;
};

