/**
 * Returns the cars the school uses for training
 * @summary List training cars
 */
export const getListCarsUrl = () => {
  return `/api/cars`;
};

export const listCars = async (options?: RequestInit): Promise<Car[]> => {
  return customFetch<Car[]>(getListCarsUrl(), {
    ...options,
    method: "GET",
  });
};

export const getListCarsQueryKey = () => {
  return [`/api/cars`] as const;
};

export const getListCarsQueryOptions = <
  TData = Awaited<ReturnType<typeof listCars>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<Awaited<ReturnType<typeof listCars>>, TError, TData>;
  request?: SecondParameter<typeof customFetch>;
}) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListCarsQueryKey();

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listCars>>> = ({
    signal,
  }) => listCars({ signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listCars>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListCarsQueryResult = NonNullable<
  Awaited<ReturnType<typeof listCars>>
>;
export type ListCarsQueryError = ErrorType<unknown>;

/**
 * @summary List training cars
 */

export function useListCars<
  TData = Awaited<ReturnType<typeof listCars>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<Awaited<ReturnType<typeof listCars>>, TError, TData>;
  request?: SecondParameter<typeof customFetch>;
}): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getListCarsQueryOptions(options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
